// ── Daily Summary Aggregator ─────────────────────────
const allRows = $input.all().map(i => i.json);

const now   = new Date();
const since = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const last24h = allRows.filter(r => {
  if (!r.createdAt) return false;
  return new Date(r.createdAt) >= since;
});

// Total count
const total = last24h.length;

// Category breakdown
const byCategory = {};
for (const r of last24h) {
  const cat = r.category ?? 'unknown';
  byCategory[cat] = (byCategory[cat] ?? 0) + 1;
}

// Priority breakdown
const byPriority = {};
for (const r of last24h) {
  const pri = r.priority ?? 'unknown';
  byPriority[pri] = (byPriority[pri] ?? 0) + 1;
}

// Top 3 keywords (simple frequency from subject+message)
const wordFreq = {};
const stopWords = new Set(['the','a','an','is','it','to','of','and','in','for','on','with','i','my','me','we','our','you','your','this','that','was','have','has','be','are','at','but','by','from']);
for (const r of last24h) {
  const words = `${r.subject ?? ''} ${r.message ?? ''}`.toLowerCase().match(/\b[a-z]{3,}\b/g) ?? [];
  for (const w of words) {
    if (!stopWords.has(w)) wordFreq[w] = (wordFreq[w] ?? 0) + 1;
  }
}
const topKeywords = Object.entries(wordFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([word, count]) => `"${word}" (${count})`);

// Build report
const report = [
  `📊 DAILY SUPPORT SUMMARY – ${now.toDateString()}`,
  `${'='.repeat(45)}`,
  ``,
  `📨 Total Tickets (last 24h): ${total}`,
  ``,
  `📂 By Category:`,
  ...Object.entries(byCategory).map(([k,v]) => `   • ${k}: ${v}`),
  ``,
  `⚡ By Priority:`,
  ...Object.entries(byPriority).map(([k,v]) => `   • ${k}: ${v}`),
  ``,
  `🔑 Top 3 Keywords:`,
  ...(topKeywords.length ? topKeywords.map(kw => `   • ${kw}`) : ['   (no data)']),
  ``,
  `${'='.repeat(45)}`,
  `Generated at ${now.toISOString()}`
].join('\n');

return [{ json: { report, total, byCategory, byPriority, topKeywords, generatedAt: now.toISOString() } }];
